		["pd-map"] = "This map is <b>ineligible for [[w:Copyright|copyright]]</b> and therefore in the [[w:Public domain|<b>public domain</b>]], because it consists entirely of information that is common property and contains no original authorship.",
		["pd-chem"] = "This image of a simple [[w:Structural formula|<b>structural formula</b>]] is <b>ineligible for [[w:Copyright|copyright]]</b> and therefore in the [[w:Public domain|<b>public domain</b>]], because it consists entirely of information that is common property and contains no original authorship.",
