i18n.vi = {
	messages = {
		["pd-flag"] = "Hình ảnh này của một <b>[[w:vi:Kỳ học|lá cờ]]</b> <b>không đủ điều kiện để bảo hộ bản quyền</b> và do đó thuộc <b>[[w:vi:Phạm vi công cộng|phạm vi công cộng]]</b>, bởi vì nó hoàn toàn chứa đựng thông tin là tài sản chung và không có tác quyền gốc.",
		["pd-shapes"] = "Hình ảnh <b>[[w:vi:Hình học|hình học đơn giản]]</b> này <b>không đủ điều kiện bảo hộ [[w:vi:Bản quyền|bản quyền]]</b> và do đó thuộc <b>[[w:vi:Phạm vi công cộng|phạm vi công cộng]]</b>, bởi vì nó hoàn toàn bao gồm các thông tin là tài sản chung và không có tác quyền gốc.",
		["pd-textlogo"] = "Hình ảnh logo này chỉ bao gồm các hình học hoặc văn bản đơn giản. Nó <b>không đạt được [[wikimediacommons:Commons:Threshold_of_originality|ngưỡng sáng tạo]]</b> cần thiết để được bảo vệ bản quyền, và do đó thuộc <b>[[w:vi:Phạm vi công cộng|phạm vi công cộng]]</b>. Mặc dù không bị hạn chế bởi bản quyền, hình ảnh này vẫn có thể chịu sự điều chỉnh của [[wikimediacommons:Commons:Non-copyright restrictions|các hạn chế phi bản quyền khác]].",
		["pd-author-with"] = "Tác phẩm này đã được tác giả của nó, $1, phát hành vào [[w:vi:Phạm vi công cộng|phạm vi công cộng]]. Điều này áp dụng trên toàn thế giới.<br/><small>Tại một số quốc gia, điều này có thể không hợp lệ về mặt pháp lý; nếu vậy:</small><br/><i>$1 cấp cho bất kỳ ai quyền sử dụng tác phẩm này cho bất kỳ mục đích nào, không kèm theo bất kỳ điều kiện nào, trừ khi luật pháp yêu cầu những điều kiện đó.</i>",
		["pd-author-self"] = "Tôi, người giữ bản quyền của tác phẩm này, qua đây phát hành tác phẩm này vào [[w:vi:Phạm vi công cộng|phạm vi công cộng]]. Điều này áp dụng trên toàn thế giới.<br/><small>Tại một số quốc gia, điều này có thể không hợp lệ về mặt pháp lý; nếu vậy:</small><br/><i>Tôi cấp cho bất kỳ ai quyền sử dụng tác phẩm này cho bất kỳ mục đích nào, không kèm theo bất kỳ điều kiện nào, trừ khi luật pháp yêu cầu những điều kiện đó.</i>",
		["pd-ineligible"] = "Tác phẩm này <b>không đủ điều kiện bảo hộ [[w:vi:Bản quyền|bản quyền]]</b> và do đó thuộc <b>[[w:vi:Phạm vi công cộng|phạm vi công cộng]]</b> bởi vì nó hoàn toàn bao gồm các thông tin là [[wikimediacommons:Commons:Threshold of originality|tài sản chung và không có tác quyền gốc]].",
		["pd-chart"] = "Biểu đồ này <b>không đủ điều kiện bảo hộ [[w:vi:Bản quyền|bản quyền]]</b> và do đó thuộc <b>[[w:vi:Phạm vi công cộng|phạm vi công cộng]]</b>, bởi vì nó hoàn toàn bao gồm các thông tin là tài sản chung và không có tác quyền gốc.",
		["pd-map"] = "Bản đồ này <b>không đủ điều kiện bảo hộ [[w:vi:Bản quyền|bản quyền]]</b> và do đó thuộc <b>[[w:vi:Phạm vi công cộng|phạm vi công cộng]]</b>, bởi vì nó hoàn toàn bao gồm các thông tin là tài sản chung và không có tác quyền gốc.",
		["pd-chem"] = "Hình ảnh của một [[w:vi:Công thức cấu tạo|<b>công thức cấu tạo</b>]] hóa học đơn giản này <b>không đủ điều kiện bảo hộ [[w:vi:Bản quyền|bản quyền]]</b> và do đó thuộc <b>[[w:vi:Phạm vi công cộng|phạm vi công cộng]]</b>, bởi vì nó hoàn toàn bao gồm các thông tin là tài sản chung và không có tác quyền gốc.",
		["pd-text"] = 'Đoạn văn bản được miêu tả <b>không đủ điều kiện bảo hộ [[w:vi:Bản quyền|bản quyền]]</b> và do đó thuộc <b>[[w:vi:Phạm vi công cộng|phạm vi công cộng]]</b> vì nó không phải là "tác phẩm văn học" hoặc loại hình được bảo vệ theo luật bản quyền địa phương. Sự kiện, dữ liệu, thông tin thiếu tính nguyên bản, phông chữ chung hay hình học cơ bản không được bảo vệ bản quyền. <small>Thẻ này không áp dụng cho mọi hình ảnh chứa văn bản, tùy thuộc vào định nghĩa pháp lý của từng quốc gia về "tác phẩm văn học".</small>',
		["pd-sign"] = "Biển báo đơn giản này <b>không đủ điều kiện bảo hộ [[w:vi:Bản quyền|bản quyền]]</b> và do đó thuộc <b>[[w:vi:Phạm vi công cộng|phạm vi công cộng]]</b>, bởi vì nó hoàn toàn bao gồm các thông tin là tài sản chung và không có tác quyền gốc.",
		["pd-wpdc"] = "Sơ đồ phân bổ (bầu cử) này <b>không đủ điều kiện bảo hộ [[w:vi:Bản quyền|bản quyền]]</b> và do đó thuộc <b>[[w:vi:Phạm vi công cộng|phạm vi công cộng]]</b>, bởi vì nó hoàn toàn bao gồm các thông tin là tài sản chung và không có tác quyền gốc.",
		
		["cc-by-sa-4.0"] = '<div style="font-size:1.4em; text-align: center; font-weight: bold;">[https://creativecommons.org/licenses/by-sa/4.0/deed.vi Ghi công–Chia sẻ tương tự 4.0 Quốc tế] (CC BY-SA 4.0)</div><ul><div style="font-size:1.2em; font-weight: bold;">Bạn được tự do:</div><li><b>Chia sẻ</b> — sao chép và phân phối lại tài liệu dưới bất kỳ phương tiện hoặc định dạng nào cho bất kỳ mục đích nào, kể cả thương mại.</li><li><b>Sửa đổi</b> — phối trộn, biến đổi và xây dựng dựa trên tài liệu cho bất kỳ mục đích nào, kể cả thương mại.</li><li>Người cấp phép không thể thu hồi những quyền tự do này miễn là bạn tuân theo các điều khoản của giấy phép.</li><div style="font-size:1.2em; font-weight: bold;">Theo các điều khoản sau:</div><li><b>Ghi công</b> — Bạn phải ghi công phù hợp, cung cấp liên kết đến giấy phép và cho biết nếu có thay đổi. Bạn có thể làm như vậy bằng bất kỳ cách thức hợp lý nào, nhưng không được gợi ý rằng người cấp phép chứng thực bạn hoặc việc sử dụng của bạn.</li><li><b>Chia sẻ tương tự</b> — Nếu bạn phối trộn, biến đổi hoặc xây dựng dựa trên tài liệu, bạn phải phân phối các đóng góp của mình theo cùng một giấy phép với bản gốc.</li><li><b>Không có hạn chế bổ sung</b> — Bạn không được áp dụng các điều khoản pháp lý hoặc biện pháp công nghệ nhằm hạn chế người khác thực hiện bất cứ điều gì mà giấy phép cho phép.</li></ul>',
		["cc-by-sa-3.0-vn"] = '<div style="font-size:1.4em; text-align: center; font-weight: bold;">[https://creativecommons.org/licenses/by-sa/3.0/vn/deed.vi Ghi công–Chia sẻ tương tự 3.0 Việt Nam] (CC BY-SA 3.0 VN)</div><ul><div style="font-size:1.2em; font-weight: bold;">Bạn được tự do:</div><li><b>Chia sẻ</b> — sao chép và phân phối lại tài liệu dưới bất kỳ phương tiện hoặc định dạng nào cho bất kỳ mục đích nào, kể cả thương mại.</li><li><b>Sửa đổi</b> — phối trộn, biến đổi và xây dựng dựa trên tài liệu cho bất kỳ mục đích nào, kể cả thương mại.</li><div style="font-size:1.2em; font-weight: bold;">Theo các điều khoản sau:</div><li><b>Ghi công</b> — Bạn phải ghi công phù hợp, cung cấp liên kết đến giấy phép và cho biết nếu có thay đổi.</li><li><b>Chia sẻ tương tự</b> — Nếu bạn phối trộn, biến đổi hoặc xây dựng dựa trên tài liệu, bạn phải phân phối các đóng góp của mình theo cùng một giấy phép với bản gốc.</li></ul>',
		
		["mit"] = '<center>Tập tin này được cấp phép theo Giấy phép Expat, hay còn được biết đến với tên gọi <b>MIT License:</b></center><hr/><i>Bản quyền © $1 $2</i><br/><br/>Qua đây, quyền lợi được cấp miễn phí cho bất kỳ người nào có được bản sao của phần mềm này và các tệp tài liệu liên quan ("Phần mềm"), được phép xử lý Phần mềm mà không có giới hạn, bao gồm nhưng không giới hạn ở quyền sử dụng, sao chép, sửa đổi, hợp nhất, xuất bản, phân phối, cấp phép lại và/hoặc bán bản sao của Phần mềm, và cho phép những người được cung cấp Phần mềm làm như vậy, với các điều kiện sau:<br/><br/>Thông báo bản quyền ở trên và thông báo cấp phép này phải được bao gồm trong tất cả các bản sao hoặc phần quan trọng của Phần mềm.<br/><br/>PHẦN MỀM ĐƯỢC CUNG CẤP "NHƯ NGUYÊN TRẠNG", KHÔNG CÓ BẤT KỲ ĐẢM BẢO NÀO, RÕ RÀNG HAY NGỤ Ý, BAO GỒM NHƯNG KHÔNG GIỚI HẠN Ở CÁC ĐẢM BẢO VỀ KHẢ NĂNG THƯƠNG MẠI, TÍNH PHÙ HỢP CHO MỘT MỤC ĐÍCH CỤ THỂ VÀ KHÔNG VI PHẠM.<hr/><center>Gửi người tải lên: MIT License có nhiều phiên bản khác nhau, bạn có thể muốn chỉ định giấy phép chính xác hơn. Nhấn {{T|CGeo}} để xem chi tiết.</center>',
		["apache"] = '<p>Bản quyền © $1 $2 </p><p>Được cấp phép theo [[w:vi:Apache License|Apache License]], Phiên bản 2.0 ("Giấy phép"); bạn không được sử dụng tệp này ngoại trừ tuân thủ Giấy phép. Bạn có thể nhận được bản sao của Giấy phép tại https://www.apache.org/licenses/LICENSE-2.0. Trừ khi luật pháp hiện hành yêu cầu hoặc có thỏa thuận bằng văn bản, phần mềm được phân phối theo Giấy phép này được phân phối trên cơ sở "NHƯ NGUYÊN TRẠNG", KHÔNG CÓ ĐẢM BẢO HOẶC ĐIỀU KIỆN DƯỚI BẤT KỲ HÌNH THỨC NÀO, dù rõ ràng hay ngụ ý. Xem Giấy phép để biết các quyền và giới hạn được chi phối cụ thể theo ngôn ngữ trong Giấy phép.</p>',
		
		["fictitious-flag"] = "Lá cờ này là hư cấu, được đề xuất hoặc không chính thức, mặc dù nó có thể trông giống với một lá cờ chính thức. Những lá cờ như vậy thường không nên được sử dụng trong các bài viết, trừ khi chúng được sử dụng không chính thức một cách rộng rãi.",
		["nazi"] = '<span style="font-size:21px;font-weight:bold;">Tuyên bố từ chối trách nhiệm pháp lý</span><br/>Hình ảnh này hiển thị (hoặc giống với) một biểu tượng từng được sử dụng bởi chính phủ Quốc xã (NSDAP/Nazi) của Đức hoặc một tổ chức có liên hệ chặt chẽ với nó, hoặc một đảng phái khác <b>đã bị [[w:vi:Tòa án Hiến pháp Liên bang Đức|Tòa án Hiến pháp Liên bang Đức]] cấm</b>.<p>Việc sử dụng phù hiệu của các tổ chức <b>đã bị cấm ở [[w:vi:Đức|Đức]]</b> (như chữ Vạn của Đức Quốc xã hoặc cờ chữ thập mũi tên) cũng có thể <b>bất hợp pháp ở Áo, Brazil, Cộng hòa Séc, Pháp, Hungary, Ba Lan, Nga, Ukraine và các quốc gia khác</b>, tùy thuộc vào bối cảnh.</p>',
		["naziflag"] = '<span style="font-size:21px;font-weight:bold;">Tuyên bố từ chối trách nhiệm pháp lý</span><br/>Hình ảnh này chứa hoặc giống với <b>cờ</b> hoặc <b>[[w:vi:Reichskriegsflagge|Cờ Chiến tranh của Đế chế]]</b> liên quan đến chính quyền Quốc xã (NSDAP/Nazi), hoặc các tổ chức liên quan chặt chẽ. Tùy thuộc vào bối cảnh và luật pháp hiện hành, việc hiển thị công khai các biểu tượng của các tổ chức <b>bị cấm ở [[w:vi:Đức|Đức]]</b> cũng có thể là <b>bất hợp pháp tại một số quốc gia khác...</b>',
		["non-nazi"] = '<span style="font-size:21px;font-weight:bold;">Tuyên bố từ chối trách nhiệm pháp lý</span><br/>Hình ảnh chữ vạn này giống với chữ vạn đã được chính phủ Quốc xã sử dụng... Tuy nhiên, lệnh cấm này không áp dụng cho chữ vạn có tính chất tôn giáo, bao gồm cả những chữ vạn được sử dụng trong Phật giáo, Ấn Độ giáo và Kỳ Na giáo.',
		["falungong"] = '<span style="font-size:21px;font-weight:bold;">Tuyên bố từ chối trách nhiệm pháp lý</span><br/>Hình ảnh này giống với biểu tượng được sử dụng bởi [[w:vi:Pháp Luân Công|Pháp Luân Công]] hoặc một tổ chức liên quan...<p>Việc sử dụng các phù hiệu tương tự như các tổ chức đã bị cấm ở Trung Quốc Đại lục <b>cũng có thể bị coi là bất hợp pháp ở [[w:vi:Nga|Nga]] và các quốc gia khác,</b> tùy thuộc vào bối cảnh.</p>',
		["communist"] = '<span style="font-size:21px;font-weight:bold;">Tuyên bố từ chối trách nhiệm pháp lý</span><br/><b>Hình ảnh này chứa một biểu tượng [[w:vi:Cấm các biểu tượng cộng sản|bị cấm]] theo luật ở một số quốc gia</b>, vì nó đại diện cho chủ nghĩa cộng sản, chủ nghĩa xã hội, hoặc một tổ chức chính trị liên quan. Hình ảnh được đề cập có thể bao gồm [[w:vi:Búa liềm|búa liềm]], [[w:vi:Sao đỏ|sao đỏ]], biểu tượng/phù hiệu, [[w:vi:Cờ đỏ (chính trị)|cờ]] hoặc hình ảnh của các nhà lãnh đạo.',
		["z"] = '<span style="font-size:21px;font-weight:bold;">Tuyên bố từ chối trách nhiệm pháp lý</span><br/>Hình ảnh này hiển thị (hoặc giống với) một biểu tượng được sử dụng bởi [[w:vi:Nga|Liên bang Nga]] và [[w:vi:Lực lượng Vũ trang Liên bang Nga|Lực lượng Vũ trang]] của quốc gia này, một tổ chức có liên hệ chặt chẽ hoặc một bên khác <b>ủng hộ hoặc tôn vinh các cuộc chiến tranh xâm lược hoặc hành vi xâm lược</b>.<p>Việc sử dụng các phù hiệu này <b>có thể bị pháp luật cấm tại Cộng hòa Séc, Đức, Kazakhstan, Kyrgyzstan, Latvia, Litva, Moldova, Ba Lan, Ukraine và các quốc gia khác</b>, tùy thuộc vào bối cảnh.</p>',
		["teikoku"] = '<span style="font-size:21px;font-weight:bold;">Tuyên bố từ chối trách nhiệm pháp lý</span><br/>Hình ảnh này hiển thị (hoặc giống với) một biểu tượng từng được Đế quốc Nhật Bản và Lực lượng Vũ trang của nó sử dụng... <b>ủng hộ hoặc tôn vinh các cuộc chiến tranh xâm lược</b>.<p>Việc sử dụng các phù hiệu <b>cũng có thể bất hợp pháp ở [[w:vi:Hàn Quốc|Hàn Quốc]], [[w:vi:Nga|Nga]] và các quốc gia khác</b>, tùy thuộc vào bối cảnh.</p>',
		["southvietnam"] = '<span style="font-size:21px;font-weight:bold;">Tuyên bố từ chối trách nhiệm pháp lý</span><br/><b>Hình ảnh này là hoặc chứa (các) biểu tượng [[w:vi:Tuyên truyền chống Nhà nước Cộng hòa xã hội chủ nghĩa Việt Nam|bị cấm]] bởi [[W:vi:Quốc hội (Việt Nam)|Quốc hội Việt Nam]]</b>, do là biểu tượng đại diện cho [[W:vi:Việt Nam Cộng hòa|Việt Nam Cộng hòa]], hoặc các cơ cấu chính quyền/tổ chức liên quan. Luật áp dụng là Điều 117 của Bộ luật Hình sự 2015.<p>Hình ảnh được đề cập có thể bao gồm [[W:vi:Quốc kỳ Việt Nam Cộng hòa|Quốc kỳ Việt Nam Cộng hòa]] và các biểu tượng/phù hiệu.</p>',
		["vietnamgroup"] = '<span style="font-size:21px;font-weight:bold;">Tuyên bố từ chối trách nhiệm pháp lý</span><br/>Hình ảnh này có chứa (các) biểu tượng được sử dụng bởi [[w:vi:Chính phủ Quốc gia Việt Nam Lâm thời|Chính phủ Quốc gia Việt Nam Lâm thời]], [[w:vi:Việt Tân|Việt Tân]], [[w:vi:FULRO|FULRO]], hoặc các nhóm liên quan. Việc sử dụng các biểu tượng này bị <b>nghiêm cấm</b> theo Điều 117 của Bộ luật hình sự 2015.<p><b>Xin lưu ý rằng tất cả các tổ chức được ghi nhận trong bản mẫu này đều được tuyên bố là tổ chức khủng bố tại Việt Nam. Các biểu tượng này chỉ được cho phép cho mục đích báo chí không mang tính phản động. Bạn hoàn toàn chịu trách nhiệm đảm bảo rằng bạn không vi phạm luật chống khủng bố.</b></p>',
		["israel"] = "Việc hiển thị hoặc sử dụng quốc kỳ Israel hoặc các phù hiệu liên quan có thể bị hạn chế hoặc cấm theo luật địa phương tại các quốc gia sau: Afghanistan, Algeria, Bangladesh, Iran, Iraq, Kuwait, Lebanon, Libya, Pakistan, Qatar, Ả Rập Xê Út, Syria, Yemen. Trước khi phân phối lại hoặc hiển thị công khai hình ảnh này, vui lòng xác minh các quy định hiện hành trong khu vực pháp lý của bạn.",
		["lgbtq"] = '<span style="font-size:21px;font-weight:bold;">Tuyên bố từ chối trách nhiệm pháp lý</span><br/>Hình ảnh hoặc tệp video này chứa một biểu tượng đại diện cho các nhóm thiểu số về tính dục và giới tính (LGBTQ).<p>Việc sử dụng các biểu tượng này <b>có thể bị trừng phạt theo luật pháp hiện hành</b> tại <b>Afghanistan, Iran, Nga, Ả Rập Xê Út, Uganda, Các Tiểu vương quốc Ả Rập Thống nhất, v.v.</b></p>',
		["antilgbtq"] = '<span style="font-size:21px;font-weight:bold;">Tuyên bố từ chối trách nhiệm pháp lý</span><br/>Hình ảnh này chứa một biểu tượng đại diện cho thái độ tiêu cực hoặc cố chấp đối với các nhóm thiểu số tính dục và giới tính.<p>Việc sử dụng các biểu tượng này nhằm mục đích phân biệt đối xử <b>có thể bị trừng phạt theo luật chống phân biệt đối xử</b> tại nhiều quốc gia.</p>',
		["apartheid"] = '<span style="font-size:21px;font-weight:bold;">Tuyên bố từ chối trách nhiệm pháp lý</span><br/>Hình ảnh này mô tả hoặc giống với cờ của Nam Phi từ năm 1928 đến năm 1994, <b>bị cấm do coi là ngôn từ kích động thù địch và có thể bị truy tố hình sự khi hiển thị công khai tại Nam Phi</b>, ngoại trừ các mục đích nghệ thuật, học thuật hoặc báo chí đích thực phục vụ lợi ích công cộng.',
		["ai"] = '<span style="font-size:21px;font-weight:bold;">Tuyên bố từ chối trách nhiệm pháp lý</span><br/><b>Hầu hết các mô hình [[w:vi:Nghệ thuật AI|AI tạo hình ảnh]] đều được đào tạo bằng cách sử dụng các tác phẩm được bảo hộ [[w:vi:Bản quyền|bản quyền]]</b>. Do đó, <b>có rủi ro là các phương tiện do AI tạo ra được tải lên Commons có thể vi phạm quyền của tác giả các tác phẩm gốc</b>.',
		
		["error-no-license"] = "Lỗi CGen: Không tìm thấy loại mã giấy phép hợp lệ.",
